import pandas as pd
import re

file_path = locals()['var_function-call-6416286234857581942']
with open(file_path, 'r') as f:
    businesses = json.load(f)

data = []
for b in businesses:
    desc = b.get('description', '')
    match = re.search(r",\s+([A-Z]{2})", desc)
    state = None
    if match:
        state = match.group(1)
    if not state:
        match2 = re.search(r" in [^,]+,\s+([A-Z]{2})", desc)
        if match2:
            state = match2.group(1)

    if state:
        try:
            rc = int(b.get('review_count', 0))
        except:
            rc = 0
        data.append({
            'state': state,
            'review_count': rc
        })

df = pd.DataFrame(data)
state_stats = df.groupby('state')['review_count'].sum().sort_values(ascending=False)

print("__RESULT__:")
print(state_stats.head(5).to_json())

